yId, Namespace, QualifiedCollectionId};\\n6\\tuse axon_core::types::{Entity, Link};\\n7\\tuse axon_schema::schema::{CollectionSchema, CollectionView};\\n8\\t\\n9\\t/// A typed index value extracted from entity data.\\n10\\t///\\n11\\t/// Values are stored in EAV index tables, one variant per [`IndexType`].\\n12\\t/// The `Ord` implementation provides the sort order used for range scans.\\n13\\t#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]\\n14\\tpub enum IndexValue {\\n15\\t    /// UTF-8 string value.\\n16\\t    String(String),\\n17\\t    /// Signed 64-bit integer.\\n18\\t    Integer(i64),\\n19\\t    /// IEEE 754 float, stored as ordered bits for BTreeMap compatibility.\\n20\\t    Float(OrderedFloat),\\n21\\t    /// Boolean value (false \u003c true).\\n22\\t    Boolean(bool),\\n23\\t}\\n24\\t\\n25\\timpl std::fmt::Display for IndexValue {\\n26\\t    fn fmt(\u0026self, f: \u0026mut std::fmt::Formatter\u003c'_\u003e) -\u003e std::fmt::Result {\\n27\\t        match self {\\n28\\t            IndexValue::String(s) =\u003e write!(f, \\\"\\\\\\\"{s}\\\\\\\"\\\"),\\n29\\t            IndexValue::Integer(n) =\u003e write!(f, \\\"{n}\\\"),\\n30\\t            IndexValue::Float(OrderedFloat(bits)) =\u003e {\\n31\\t                write!(f, \\\"{}\\\", f64::from_bits(*bits))\\n32\\t            }\\n33\\t            IndexValue::Boolean(b) =\u003e write!(f, \\\"{b}\\\"),\\n34\\t        }\\n35\\t    }\\n36\\t}\\n37\\t\\n38\\t/// Wrapper for f64 that implements `Eq` and `Ord` via total ordering on bits.\\n39\\t///\\n40\\t/// NaN values are sorted after all other values. This enables use as a\\n41\\t/// BTreeMap key.\\n42\\t#[derive(Debug, Clone, Copy)]\\n43\\tpub struct OrderedFloat(pub u64);\\n44\\t\\n45\\timpl OrderedFloat {\\n46\\t    pub fn new(val: f64) -\u003e Self {\\n47\\t        Self(val.to_bits())\\n48\\t    }\\n49\\t\\n50\\t    pub fn value(\u0026self) -\u003e f64 {\\n51\\t        f64::from_bits(self.0)\\n52\\t    }\\n53\\t}\\n54\\t\\n55\\timpl PartialEq for OrderedFloat {\\n56\\t    fn eq(\u0026self, other: \u0026Self) -\u003e bool {\\n57\\t        self.0 == other.0\\n58\\t    }\\n59\\t}\\n60\\timpl Eq for OrderedFloat {}\\n61\\t\\n62\\timpl std::hash::Hash for OrderedFloat {\\n63\\t    fn hash\u003cH: std::hash::Hasher\u003e(\u0026self, state: \u0026mut H) {\\n64\\t        self.0.hash(state);\\n65\\t    }\\n66\\t}\\n67\\t\\n68\\timpl PartialOrd for OrderedFloat {\\n69\\t    fn partial_cmp(\u0026self, other: \u0026Self) -\u003e Option\u003cstd::cmp::Ordering\u003e {\\n70\\t        Some(self.cmp(other))\\n71\\t    }\\n72\\t}\\n73\\t\\n74\\timpl Ord for OrderedFloat {\\n75\\t    fn cmp(\u0026self, other: \u0026Self) -\u003e std::cmp::Ordering {\\n76\\t        let a = f64::from_bits(self.0);\\n77\\t        let b = f64::from_bits(other.0);\\n78\\t        a.total_cmp(\u0026b)\\n79\\t    }\\n80\\t}\\n81\\t\\n82\\t/// Extract an [`IndexValue`] from a JSON value according to the declared index type.\\n83\\t///\\n84\\t/// Returns `None` if the value is null, missing, or has a type mismatch\\n85\\t/// (per FEAT-013: mismatched types are not indexed, not errors).\\n86\\tpub fn extract_index_value(\\n87\\t    json_val: \u0026serde_json::Value,\\n88\\t    index_type: \u0026axon_schema::schema::IndexType,\\n89\\t) -\u003e Option\u003cIndexValue\u003e {\\n90\\t    use axon_schema::schema::IndexType;\\n91\\t    match index_type {\\n92\\t        IndexType::String =\u003e json_val.as_str().map(|s| IndexValue::String(s.to_string())),\\n93\\t        IndexType::Integer =\u003e json_val.as_i64().map(IndexValue::Integer),\\n94\\t        IndexType::Float =\u003e json_val\\n95\\t            .as_f64()\\n96\\t            .map(|f| IndexValue::Float(OrderedFloat::new(f))),\\n97\\t        IndexType::Boolean =\u003e json_val.as_bool().map(IndexValue::Boolean),\\n98\\t        IndexType::Datetime =\u003e {\\n99\\t            // Datetimes are stored as strings for ordering purposes.\\n100\\t            json_val.as_str().map(|s| IndexValue::String(s.to_string()))\\n101\\t        }\\n102\\t    }\\n103\\t}\\n104\\t\\n105\\t/// A compound index key: ordered list of field values for multi-field indexes.\\n106\\t///\\n107\\t/// Implements `Ord` lexicographically, enabling prefix matching via\\n108\\t/// BTreeMap range scans.\\n109\\t#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]\\n110\\tpub struct CompoundKey(pub Vec\u003cIndexValue\u003e);\\n111\\t\\n112\\t/// Extract a compound key from entity data given a compound index definition.\\n113\\t///\\n114\\t/// Returns `None` if any field in the compound key is null/missing/type-mismatch,\\n115\\t/// since compound index entries require all fields to be present.\\n116\\tpub fn extract_compound_key(\\n117\\t    data: \u0026serde_json::Value,\\n118\\t    fields: \u0026[axon_schema::schema::CompoundIndexField],\\n119\\t) -\u003e Option\u003cCompoundKey\u003e {\\n120\\t    let mut values = Vec::with_capacity(fields.len());\\n121\\t    for f in fields {\\n122\\t        let json_val = resolve_field_path(data, \u0026f.field)?;\\n123\\t        let val = extract_index_value(json_val, \u0026f.index_type)?;\\n124\\t        values.push(val);\\n125\\t    }\\n126\\t    Some(CompoundKey(values))\\n127\\t}\\n128\\t\\n129\\t/// Navigate a dotted field path in a JSON value.\\n130\\t///\\n131\\t/// E.g., `\\\"address.city\\\"` resolves `{\\\"address\\\": {\\\"city\\\": \\\"NY\\\"}}` to `\\\"NY\\\"`.\\n132\\tpub fn resolve_field_path\u003c'a\u003e(\\n133\\t    data: \u0026'a serde_json::Value,\\n134\\t    path: \u0026str,\\n135\\t) -\u003e Option\u003c\u0026'a serde_json::Value\u003e {\\n136\\t    let mut current = data;\\n137\\t    for segment in path.split('.') {\\n138\\t        current = current.get(segment)?;\\n139\\t    }\\n140\\t    Some(current)\\n141\\t}\\n142\\t\\n143\\t/// Abstraction over Axon's backing storage.\\n144\\t///\\n145\\t/// Implementations wrap specific databases (SQLite, PostgreSQL, FoundationDB).\\n146\\t/// All operations are executed within the context of the adapter's internal\\n147\\t/// transaction semantics.\\n148\\tpub trait StorageAdapter: Send + Sync {\\n149\\t    /// Retrieves an entity by collection and ID.\\n150\\t    fn get(\u0026self, collection: \u0026CollectionId, id: \u0026EntityId) -\u003e Result\u003cOption\u003cEntity\u003e, AxonError\u003e;\\n151\\t\\n152\\t    /// Stores an entity, overwriting any existing entity with the same ID.\\n153\\t    /// Use this for initial inserts. For versioned updates, use [`compare_and_swap`].\\n154\\t    fn put(\u0026mut self, entity: Entity) -\u003e Result\u003c(), AxonError\u003e;\\n155\\t\\n156\\t    /// Deletes an entity. Returns `Ok(())` whether or not the entity existed.\\n157\\t    fn delete(\u0026mut self, collection: \u0026CollectionId, id: \u0026EntityId) -\u003e Result\u003c(), AxonError\u003e;\\n158\\t\\n159\\t    /// Returns the number of entities in the given collection.\\n160\\t    fn count(\u0026self, collection: \u0026CollectionId) -\u003e Result\u003cusize, AxonError\u003e;\\n161\\t\\n162\\t    /// Returns entities in a collection ordered by entity ID.\\n163\\t    ///\\n164\\t    /// - `start`: inclusive lower bound (no lower bound if `None`)\\n165\\t    /// - `end`: inclusive upper bound (no upper bound if `None`)\\n166\\t    /// - `limit`: maximum number of results (unlimited if `None`)\\n167\\t    fn range_scan(\\n168\\t        \u0026self,\\n169\\t        collection: \u0026CollectionId,\\n170\\t        start: Option\u003c\u0026EntityId\u003e,\\n171\\t        end: Option\u003c\u0026EntityId\u003e,\\n172\\t        limit: Option\u003cusize\u003e,\\n173\\t    ) -\u003e Result\u003cVec\u003cEntity\u003e, AxonError\u003e;\\n174\\t\\n175\\t    /// Atomically updates an entity using optimistic concurrency control (OCC).\\n176\\t    ///\\n177\\t    /// Writes `entity` only if the current stored version equals `expected_version`.\\n178\\t    /// On success, the stored version is incremented to `expected_version + 1` and\\n179\\t    /// the updated entity is returned.\\n180\\t    ///\\n181\\t    /// Returns [`AxonError::ConflictingVersion`] if the version does not match or\\n182\\t    /// the entity does not exist.\\n183\\t    fn compare_and_swap(\\n184\\t        \u0026mut self,\\n185\\t        entity: Entity,\\n186\\t        expected_version: u64,\\n187\\t    ) -\u003e Result\u003cEntity, AxonError\u003e;\\n188\\t\\n189\\t    /// Atomically inserts `entity` only if no live entity currently exists.\\n190\\t    ///\\n191\\t    /// This is used for rollback/recovery flows that recreate a deleted entity\\n192\\t    /// after the caller has already validated the deleted version via audit\\n193\\t    /// history. `expected_absent_version` is echoed back in\\n194\\t    /// [`AxonError::ConflictingVersion`] when another writer recreated the\\n195\\t    /// entity first.\\n196\\t    fn create_if_absent(\\n197\\t        \u0026mut self,\\n198\\t        entity: Entity,\\n199\\t        expected_absent_version: u64,\\n200\\t    ) -\u003e Result\u003cEntity, AxonError\u003e;\\n201\\t\\n202\\t    /// Begin a storage-level transaction.\\n203\\t    ///\\n204\\t    /// After this call, all writes are buffered or protected until [`commit_tx`]\\n205\\t    /// or [`abort_tx`] is called. Callers must call exactly one of those to\\n206\\t    /// end the transaction.\\n207\\t    ///\\n208\\t    /// The default implementation is a no-op (suitable for adapters whose\\n209\\t    /// mutation methods are already atomic or whose concurrency model does\\n210\\t    /// not require explicit transactions).\\n211\\t    fn begin_tx(\u0026mut self) -\u003e Result\u003c(), AxonError\u003e {\\n212\\t        Ok(())\\n213\\t    }\\n214\\t\\n215\\t    /// Commit the current transaction, making all buffered writes durable.\\n216\\t    ///\\n217\\t    /// Returns an error if no transaction is active.\\n218\\t    /// The default implementation is a no-op.\\n219\\t    fn commit_tx(\u0026mut self) -\u003e Result\u003c(), AxonError\u003e {\\n220\\t        