d collection has been explicitly created.\\n432\\t    ///\\n433\\t    /// Implementations must persist this so the collection survives process\\n434\\t    /// restart. The default implementation is a no-op.\\n435\\t    fn register_collection(\u0026mut self, collection: \u0026CollectionId) -\u003e Result\u003c(), AxonError\u003e {\\n436\\t        self.register_collection_in_namespace(collection, \u0026Namespace::default_ns())\\n437\\t    }\\n438\\t\\n439\\t    /// Record that a named collection belongs to a specific namespace.\\n440\\t    ///\\n441\\t    /// Implementations that do not yet distinguish namespaces may ignore the\\n442\\t    /// namespace and treat all collections as belonging to `default.default`.\\n443\\t    fn register_collection_in_namespace(\\n444\\t        \u0026mut self,\\n445\\t        collection: \u0026CollectionId,\\n446\\t        _namespace: \u0026Namespace,\\n447\\t    ) -\u003e Result\u003c(), AxonError\u003e {\\n448\\t        let _ = collection;\\n449\\t        Ok(())\\n450\\t    }\\n451\\t\\n452\\t    /// Return whether a collection is registered within a specific namespace.\\n453\\t    fn collection_registered_in_namespace(\\n454\\t        \u0026self,\\n455\\t        collection: \u0026CollectionId,\\n456\\t        namespace: \u0026Namespace,\\n457\\t    ) -\u003e Result\u003cbool, AxonError\u003e {\\n458\\t        Ok(self\\n459\\t            .list_namespace_collections(namespace)?\\n460\\t            .contains(collection))\\n461\\t    }\\n462\\t\\n463\\t    /// Remove a collection from the registry.\\n464\\t    ///\\n465\\t    /// Returns `Ok(())` whether or not the collection was registered.\\n466\\t    /// The default implementation is a no-op.\\n467\\t    fn unregister_collection(\u0026mut self, collection: \u0026CollectionId) -\u003e Result\u003c(), AxonError\u003e {\\n468\\t        let _ = collection;\\n469\\t        Ok(())\\n470\\t    }\\n471\\t\\n472\\t    /// Return all explicitly-registered collection names, in ascending order.\