e axon_core::auth::{AuthError, JwtClaims, Op, ResolvedIdentity, TenantId, UserId};\\nuse axon_storage::adapter::StorageAdapter;\\n\\n// ── JwtIssuer ────────────────────────────────────────────────────────────────\\n\\n/// Signs and verifies JWTs using HS256.\\npub struct JwtIssuer {\\n    secret: Vec\u003cu8\u003e,\\n    /// Issuer identifier placed in the `iss` claim and verified on every request.\\n    pub issuer_id: String,\\n}\\n\\nimpl JwtIssuer {\\n    /// Create a new issuer with the given HMAC secret and issuer ID.\\n    pub fn new(secret: Vec\u003cu8\u003e, issuer_id: String) -\u003e Self {\\n        Self { secret, issuer_id }\\n    }\\n\\n    /// Sign `claims` into a compact HS256 JWT string.\\n    pub fn issue(\u0026self, claims: \u0026JwtClaims) -\u003e Result\u003cString, AuthError\u003e {\\n        encode(\\n            \u0026Header::new(Algorithm::HS256),\\n            claims,\\n            \u0026EncodingKey::from_secret(\u0026self.secret),\\n        )\\n        .map_err(|_| AuthError::CredentialMalformed)\\n    }\\n\\n    /// Verify the signature and deserialise the claims.\\n    ///\\n    /// Time-based checks (`exp`, `nbf`) are intentionally skipped here; the\\n    /// middleware performs them manually with a configurable skew budget.\\n    pub fn verify(\u0026self, token: \u0026str) -\u003e Result\u003cJwtClaims, AuthError\u003e {\\n        let mut validation = Validation::new(Algorithm::HS256);\\n        validation.validate_exp = false;\\n        validation.validate_nbf = false;\\n        validation.validate_aud = false;\\n        validation.required_spec_claims = HashSet::new();\\n\\n        decode::\u003cJwtClaims\u003e(token, \u0026DecodingKey::from_secret(\u0026self.secret), \u0026validation)\\n            .map(|td| td.claims)\\n            .map_err(|e| match e.kind() {\\n                jsonwebtoken::errors::ErrorKind::InvalidSignature =\u003e AuthError::CredentialInvalid,\\n                jsonwebtoken::errors::ErrorKind::Json(_) =\u003e AuthError::CredentialMalformed,\\n                jsonwebtoken::errors::ErrorKind::Base64(_) =\u003e AuthError::CredentialMalformed,\\n                jsonwebtoken::errors::ErrorKind::Utf8(_) =\u003e AuthError::CredentialMalformed,\\n                jsonwebtoken::errors::ErrorKind::InvalidToken =\u003e AuthError::CredentialMalformed,\\n                _ =\u003e AuthError::CredentialMalformed,\\n            })\\n    }\\n}\\n\\n// ── InMemoryRevocationCache ───────────────────────────────────────────────────\\n\\n/// In-process cache of revoked JWT IDs.\\n///\\n/// The middleware checks this first before falling back to the storage adapter,\\n/// avoiding a round-trip to storage on every request for known-revoked tokens.\\n#[derive(Default)]\\npub struct InMemoryRevocationCache {\\n    inner: RwLock\u003cHashSet\u003cUuid\u003e\u003e,\\n}\\n\\nimpl InMemoryRevocationCache {\\n    /// Create an empty cache.\\n    pub fn new() -\u003e Self {\\n        Self::default()\\n    }\\n\\n    /// Returns `true` if `jti` is in the cache.\\n    pub fn contains(\u0026self, jti: \u0026Uuid) -\u003e bool {\\n        self.inner\\n            .read()\\n            .map(|g| g.contains(jti))\\n            .unwrap_or(false)\\n    }\\n\\n    /// Add `jti` to the cache.\\n    pub fn insert(\u0026self, jti: Uuid) {\\n        if let Ok(mut g) = self.inner.write() {\\n            g.insert(jti);\\n        }\\n    }\\n}\\n\\n// ── AuthPipelineState ─────────────────────────────────────────────────────────\\n\\n/// Shared state for the JWT verification middleware.\\n///\\n/// Wrap in `Arc` before passing to `axum::middleware::from_fn_with_state`.\\n#[derive(Clone)]\\npub struct AuthPipelineState {\\n    /// Token issuer / verifier.\\n    pub issuer: Arc\u003cJwtIssuer\u003e,\\n    /// Fast in-process revocation check.\\n    pub revocation_cache: Arc\u003cInMemoryRevocationCache\u003e,\\n    /// Authoritative storage for user, membership, and revocation data.\\n    pub storage: Arc\u003cMutex\u003cBox\u003cdyn StorageAdapter + Send + Sync\u003e\u003e\u003e,\\n}\\n\\nimpl AuthPipelineState {\\n    /// Convenience constructor.\\n    pub fn new(issuer: JwtIssuer, storage: Box\u003cdyn StorageAdapter + Send + Sync\u003e) -\u003e Self {\\n        Self {\\n            issuer: Arc::new(issuer),\\n            revocation_cache: Arc::new(InMemoryRevocationCache::new()),\\n            storage: Arc::new(Mutex::new(storage)),\\n        }\\n    }\\n}\\n\\n// ── Middleware ────────────────────────────────────────────────────────────────\\n\\n/// Axum middleware that enforces the ADR-018 §4 JWT verification order.\\n///\\n/// Install with:\\n/// ```ignore\\n/// Router::new()\\n///     .route(\\\"/tenants/:t/databases/:db/…\\\", …)\\n///     .layer(axum::middleware::from_fn_with_state(\\n///         Arc::new(state),\\n///         jwt_verify_layer,\\n///     ))\\n/// ```\\npub async fn jwt_verify_layer(\\n    State(state): State\u003cArc\u003cAuthPipelineState\u003e\u003e,\\n    request: axum::extract::Request,\\n    next: Next,\\n) -\u003e Response {\\n    let path = request.uri().path().to_string();\\n\\n    // Skip middleware for paths that are not data-plane paths.\\n    let Some((tenant, database)) = extract_tenant_database(\u0026path) else {\\n        return next.run(request).await;\\n    };\\n\\n    let tenant = tenant.to_string();\\n    let database = database.to_string();\\n    let method = request.method().clone();\\n    let headers = request.headers().clone();\\n\\n    match verify_request(\u0026state, \u0026headers, \u0026method, \u0026tenant, \u0026database) {\\n        Ok(identity) =\u003e {\\n            let mut request = request;\\n            request.extensions_mut().insert(identity);\\n            next.run(request).await\\n        }\\n        Err(err) =\u003e AuthErrorResponse(err).into_response(),\\n    }\\n}\\n\\n// ── Core verification logic ───────────────────────────────────────────────────\\n\\nfn verify_request(\\n    state: \u0026AuthPipelineState,\\n    headers: \u0026HeaderMap,\\n    method: \u0026Method,\\n    tenant: \u0026str,\\n    database: \u0026str,\\n) -\u003e Result\u003cResolvedIdentity, AuthError\u003e {\\n    // Step 1: Extract Bearer token.\\n    let token = extract_bearer_token(headers)?;\\n\\n    // Step 2: Verify JWT signature and structure.\\n    let claims = state.issuer.verify(token)?;\\n\\n    // Step 3: Check iss.\\n    if claims.iss != state.issuer.issuer_id {\\n        return Err(AuthError::CredentialForeignIssuer);\\n    }\\n\\n    // Step 4: Check exp/nbf with 30 s skew.\\n    let now = SystemTime::now()\\n        .duration_since(UNIX_EPOCH)\\n        .unwrap_or_default()\\n        .as_secs();\\n    const SKEW: u64 = 30;\\n    // Expired: exp + skew \u003c now  ↔  expired more than `skew` seconds ago\\n    if claims.exp.saturating_add(SKEW) \u003c now {\\n        return Err(AuthError::CredentialExpired);\\n    }\\n    // Not yet valid: nbf \u003e now + skew  ↔  valid more than `skew` seconds from now\\n    if claims.nbf \u003e now.saturating_add(SKEW) {\\n        return Err(AuthError::CredentialNotYetValid);\\n    }\\n\\n    // Step 5: Check JTI revocation (cache first, then storage).\\n    let jti_uuid: Uuid = claims\\n        .jti\\n        .parse()\\n        .map_err(|_| AuthError::CredentialMalformed)?;\\n    if state.revocation_cache.contains(\u0026jti_uuid) {\\n        return Err(AuthError::CredentialRevoked);\\n    }\\n    {\\n        let storage = state\\n            .storage\\n            .lock()\\n            .map_err(|_| AuthError::Unauthenticated)?;\\n        if storage\\n            .is_jti_revoked(jti_uuid)\\n            .map_err(|_| AuthError::Unauthenticated)?\\n        {\\n            // Populate the cache so subsequent checks avoid another storage round-trip.\\n            drop(storage);\\n            state.revocation_cache.insert(jti_uuid);\\n            return Err(AuthError::CredentialRevoked);\\n        }\\n    }\\n\\n    // Step 6: Compare aud to URL tenant.\\n    if claims.aud != tenant {\\n        return Err(AuthError::CredentialWrongTenant);\\n    }\\n\\n    // Step 7: Look up user, check suspension.\\n    let user_id = UserId::new(\u0026claims.sub);\\n    let user = {\\n        let storage = state\\n            .storage\\n            .lock()\\n            .map_err(|_| AuthError::Unauthenticated)?;\\n        storage\\n            .get_user(user_id.clone())\\n            .map_err(|_| AuthError::UserSuspended)?\\n            .ok_or(AuthError::UserSuspended)?\\n    };\\n    if user.suspended_at_ms.is_some() {\\n        return Err(AuthError::UserSuspended);\\n    }\\n\\n    // Step 8: Check tenant membership.\\n    let tenant_id = TenantId::new(tenant);\\n    {\\n        let storage = state\\n            .storage\\n            .lock()\\n            .map_err(|_| AuthError::Unauthenticated)?;\\n        storage\\n            .get_tenant_member(tenant_id.clone(), user_id.clone())\\n            .map_err(|_| AuthError::NotATenantMember)?\\n            .ok_or(AuthError::NotATenantMember)?;\\n    }\\n\\n    // Step 9: Walk grants for the URL database + HTTP-method-derived op.\\n    let granted_db = claims\\n        .grants\\n        .find_database(database)\\n        .ok_or(AuthError::DatabaseNotGranted)?;\\n\\n    let required_op = if method == Method::GET {\\n        Op::Read\\n    } else {\\n        Op::Write\\n    };\\n    if !granted_db.has_op(required_op) {\\n        return Err(AuthError::OpNotGranted);\\n    }\\n\\n    Ok(ResolvedIdentity {\\n        user_id,\\n        tenant_id,\\n        grants: claims.grants,\\n    })\\n}\\n\\n// ── Helpers ───────────────────────────────────────────────────────────────────\\n\\n/// Extract the `Bearer \u003ctoken\u003e` value from the `Authorization` header.\\nfn extract_bearer_token(headers: \u0026HeaderMap) -\u003e Result\u003c\u0026str, AuthError\u003e {\\n    let auth_header = headers\\n        .get(http::header::AUTHORIZATION)\\n        .ok_or(AuthError::Unauthenticated)?;\\n\\n    let auth_str = auth_header\\n        .to_str()\\n        .map_err(|_| AuthError::CredentialMalformed)?;\\n\\n    auth_str\\n        .strip_prefix(\\\"Bearer \\\")\\n        .ok_or(AuthError::CredentialMalformed)\\n}\\n\\n/// Extract `(tenant, database)` from a data-plane URL path.\\n///\\n/// Returns `Some((tenant, database))` for paths matching\\n/// `/tenants/{tenant}/databases/{database}/…`, `None` otherwise.\\n/// Non-data-plane paths skip the middleware entirely.\\npub fn extract_tenant_database(path: \u0026str) -\u003e Option\u003c(\u0026str, \u0026str)\u003e {\\n    let path = path.strip_prefix('/')?;\\n    let mut parts = path.splitn(5, '/');\\n    match (parts.next(), parts.next(), parts.next(), parts.next()) {\\n        (Some(\\\"tenants\\\"), Some(tenant), Some(\\\"databases\\\"), Some(rest))\\n            if !tenant.is_empty() \u0026\u0026 !rest.is_empty() =\u003e\\n        {\\n            let database = rest.split('/').next()?;\\n            if database.is_empty() {\\n                None\\n            } else {\\n                Some((tenant, database))\\n            }\\n        }\\n        _ =\u003e None,\\n    }\\n}\\n\\n// ── AuthError → axum Response ─────────────────────────────────────────────────\\n\\n/// Newtype wrapper that lets us implement `IntoResponse` for `AuthError` in\\n/// this crate (orphan-rule: neither `IntoResponse` nor `AuthError` is local).\\npub struct AuthErrorResponse(pub AuthError);\\n\\nimpl IntoResponse for AuthErrorResponse {\\n    fn into_response(self) -\u003e Response {\\n        let status = StatusCode::from_u16(self.0.status_code())\\n            .unwrap_or(StatusCode::INTERNAL_SERVER_ERROR);\\n        let body = json!({\\n            \\\"error\\\": {\\n                \\\"code\\\": self.0.error_code(),\\n                \\\"message\\\": self.0.to_string()\\n            }\\n        });\\n        (status, axum::Json(body)).into_response()\\n    }\\n}\\n\",\"structuredPatch\":[],\"originalFile\":null}}\n{\"type\":\"assistant\",\"message\":{\"model\":\"claude-sonnet-4-6\",\"id\":\"msg_01EWep71cAAMLoRScPgK8eLz\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"text\",\"text\":\"Now wire it into `lib.rs`:\"}],\"stop_reason\":null,\"stop_sequence\":null,\"stop_details\":null,\"usage\":{\"input_tokens\":1,\"cache_creation_input_tokens\":4023,\"cache_read_input_tokens\":118798,\"cache_creation\":{\"ephemeral_5m_input_tokens\":0,\"ephemeral_1h_input_tokens\":4023},\"output_tokens\":2,\"service_tier\":\"standard\",\"inference_geo\":\"not_available\"},\"context_management\":null},\"parent_tool_use_id\":null,\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"9cc0999e-3d90-4502-b75a-235abf6a3bd0\"}\n{\"type\":\"assistant\",\"message\":{\"model\":\"claude-sonnet-4-6\",\"id\":\"msg_01EWep71cAAMLoRScPgK8eLz\",\"type\":\"message\",\"role\":\"assistant\",\"content\":[{\"type\":\"tool_use\",\"id\":\"toolu_011h1UzxHy4JUsoKQ5w9FyCb\",\"name\":\"Edit\",\"input\":{\"replace_all\":false,\"file_path\":\"/tmp/ddx-exec-wt/.execute-bead-wt-axon-dccbdf73-20260415T013041-1340da9f/crates/axon-server/src/lib.rs\",\"old_string\":\"pub mod actor_scope;\\npub mod auth;\\nmod collection_listing;\\npub(crate) mod embedded_ui;\\npub mod control_plane;\\npub mod control_plane_routes;\\npub mod cors_config;\\npub mod user_roles;\\npub mod gateway;\\npub mod idempotency;\\npub(crate) mod mcp_http;\\npub mod mcp_stdio;\\npub mod rate_limit;\\npub mod schema_registry;\\npub mod serve;\\npub mod service;\\npub mod tenant_router;\\n\\npub use auth::{AuthContext, AuthMode, Identity, Role};\\npub use mcp_stdio::run_mcp_stdio;\\npub use service::AxonServiceImpl;\",\"new_string\":\"pub mod actor_scope;\\npub mod auth;\\npub mod auth_pipeline;\\nmod collection_listing;\\npub(crate) mod embedded_ui;\\npub mod control_plane;\\npub mod control_plane_routes;\\npub mod cors_config;\\npub mod user_roles;\\npub mod gateway;\\npub mod idempotency;\\npub(crate) mod mcp_http;\\npub mod mcp_stdio;\\npub mod rate_limit;\\npub mod schema_registry;\\npub mod serve;\\npub mod service;\\npub mod tenant_router;\\n\\npub use auth::{AuthContext, AuthMode, Identity, Role};\\npub use auth_pipeline::{InMemoryRevocationCache, JwtIssuer, jwt_verify_layer};\\npub use mcp_stdio::run_mcp_stdio;\\npub use service::AxonServiceImpl;\"},\"caller\":{\"type\":\"direct\"}}],\"stop_reason\":null,\"stop_sequence\":null,\"stop_details\":null,\"usage\":{\"input_tokens\":1,\"cache_creation_input_tokens\":4023,\"cache_read_input_tokens\":118798,\"cache_creation\":{\"ephemeral_5m_input_tokens\":0,\"ephemeral_1h_input_tokens\":4023},\"output_tokens\":2,\"service_tier\":\"standard\",\"inference_geo\":\"not_available\"},\"context_management\":null},\"parent_tool_use_id\":null,\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"753bfbef-7043-4d80-9535-663d6d911187\"}\n{\"type\":\"user\",\"message\":{\"role\":\"user\",\"content\":[{\"tool_use_id\":\"toolu_011h1UzxHy4JUsoKQ5w9FyCb\",\"type\":\"tool_result\",\"content\":\"The file /tmp/ddx-exec-wt/.execute-bead-wt-axon-dccbdf73-20260415T013041-1340da9f/crates/axon-server/src/lib.rs has been updated successfully.\"}]},\"parent_tool_use_id\":null,\"session_id\":\"80f0eb9d-4064-4d06-8560-e247ce1170f2\",\"uuid\":\"dce9764b-3a9a-4cb1-bbe3-881d04250e90\",\"timestamp\":\"2026-04-15T01:42:32.731Z\",\"tool_use_result\":{\"filePath\":\"/tmp/ddx-exec-wt/.execute-bead-wt-axon-dccbdf73-20260415T013041-1340da9f/crates/axon-server/src/lib.rs\",\"oldString\":\"pub mod actor_scope;\\npub mod auth;\\nmod collection_listing;\\npub(crate) mod embedded_ui;\\npub mod control_plane;\\npub mod control_plane_routes;\\npub mod cors_config;\\npub mod user_roles;\\npub mod gateway;\\npub mod idempotency;\\npub(crate) mod mcp_http;\\npub mod mcp_stdio;\\npub mod rate_limit;\\npub mod schema_registry;\\npub mod serve;\\npub mod service;\\npub mod tenant_router;\\n\\npub use auth::{AuthContext, AuthMode, Identity, Role};\\npub use mcp_stdio::run_mcp_stdio;\\npub use service::AxonServiceImpl;\",\"newString\":\"pub mod actor_scope;\\npub mod auth;\\npub mod auth_pipeline;\\nmod collection_listing;\\npub(crate) mod embedded_ui;\\npub mod control_plane;\\npub mod control_plane_routes;\\npub mod cors_config;\\npub mod user_roles;\\npub mod gateway;\\npub mod idempotency;\\npub(crate) mod mcp_http;\\npub mod mcp_stdio;\\npub mod rate_limit;\\npub mod schema_registry;\\npub mod serve;\\npub mod service;\\npub mod tenant_router;\\n\\npub use auth::{AuthContext, AuthMode, Identity, Role};\\npub use auth_pipeline::{InMemoryRevocationCache, JwtIssuer, jwt_verify_layer};\\npub use mcp_stdio::run_mcp_stdio;\\npub use service::AxonServiceImpl;\",\"originalFile\":\"//! Axon server — HTTP gateway, gRPC service, MCP stdio, and authentication.\\n//!\\n//! # Authentication\\n//!\\n//! Identity is resolved once per request by [`auth::AuthContext`] and\\n//! injected as a typed extension.  Three modes are supported:\\n//!\\n//! | Mode | Flag | Actor | Role |\\n//! |------|------|-------|------|\\n//! | `NoAuth` | `--no-auth` | `\\\"anonymous\\\"` | Admin |\\n//! | `Tailscale` | *(default)* | node name | from ACL tags |\\n//! | `Guest` | `--guest-role \u003crole\u003e` | `\\\"guest\\\"` | configured role |\\n//!\\n//! In `Tailscale` mode the server contacts the local Tailscale daemon over its\\n//! Unix socket (`/run/tailscale/tailscaled.sock` by default) and calls\\n//! `/localapi/v0/whois?addr=\u003cpeer\u003e` to resolve the connecting node's identity.\\n//! Resolved identities are cached by peer IP for the duration of\\n//! `--auth-cache-ttl-secs` (default 60 s).\\n//!\\n//! ACL tag → role mapping:\\n//! - `tag:axon-admin` → [`Role::Admin`]\\n//! - `tag:axon-write` / `tag:axon-agent` → [`Role::Write`]\\n//! - `tag:axon-read` → [`Role::Read`]\\n//! - no matching tag → `--tailscale-default-role` (default `read`)\\n//!\\n//! Connections that are not on the tailnet are rejected with HTTP 401 / gRPC\\n//! `UNAUTHENTICATED`.  If the Tailscale daemon is unreachable the server\\n//! returns HTTP 503 / gRPC `UNAVAILABLE`.\\n//!\\n//! # Request flow\\n//!\\n//! ```text\\n//! TCP accept\\n//!   └─ authenticate_http_request  (gateway.rs middleware)\\n//!        ├─ AuthContext::resolve_peer  →  Identity\\n//!        └─ insert Identity into request extensions\\n//!             └─ route handler\\n//!                  ├─ extract Extension\u003cIdentity\u003e\\n//!                  ├─ identity.require_read() / require_write() / require_admin()\\n//!                  └─ handler logic\\n//! ```\\n//!\\n//! gRPC follows the same pattern via [`service::AxonServiceImpl::authorize`].\\npub mod actor_scope;\\npub mod auth;\\nmod collection_listing;\\npub(crate) mod embedded_ui;\\npub mod control_plane;\\npub mod control_plane_routes;\\npub mod cors_config;\\npub mod user_roles;\\npub mod gateway;\\npub mod idempotency;\\npub(crate) mod mcp_http;\\npub mod mcp_stdio;\\npub mod rate_limit;\\npub mod schema_registry;\\npub mod serve;\\npub mod service;\\npub mod tenant_router;\\n\\npub use auth::{AuthContext, AuthMode, Identity, Role};\\npub use mcp_stdio::run_mcp_stdio;\\npub use service::AxonServiceImpl;\\n\",\"structuredPatch\":[{\"oldStart\":43,\"oldLines\":6,\"newStart\":43,\"newLines\":7,\"lines\":[\" //! gRPC follows the same pattern via [`service::AxonServiceImpl::authorize`].\",\" pub mod actor_scope;\",\" pub mod auth;\",\"+pub mod auth_pipeline;\",\" mod collection_listing;\",\" pub(crate) mod embedded_ui;\",\" pub mod control_plane;\"]},{\"oldStart\":60,\"oldLines\":5,\"newStart\":61,\"newLines\":6,\"lines\":[\" pub mod tenant_router;\",\" \",\" pub use auth::{AuthContext, AuthMode, Identity, Role};\",\"+pub use auth_pipeline::{InMemoryRevocationCache, JwtIssuer, jwt_verify_layer};\",\" pub use mcp_stdio::run_mcp_stdio;\",\" pub use service::AxonServiceImpl;\"]}],\"userModified\":false,\"replaceAll\":false}}\n{\"type\":\"assistant\",\"message\":{\"model\":\"claude-sonnet-4-6\",\"id\":\"msg_011zUAwXWxp7jsink5ubS91u\",\"type